parameters.jsCode:
const aiRaw = $('Message a model').first().json;
const aiResponse = aiRaw.output[0].content[0].text;

const edaNode = $('Code2').first().json;

const today = new Date();
const startOfYear = new Date(today.getFullYear(), 0, 1);
const weekNum = Math.ceil(((today - startOfYear) / 86400000 + 1) / 7);
const dayName = today.toLocaleDateString('en-US', { weekday: 'long' });
const filename = `manufacturing_eda_W${weekNum}_${dayName}.xlsx`;

const excelRows = edaNode.raw.map(r => ({
  json: {
    date: r.date,
    product: r.product,
    reason: r.reason,
    classification: r.classification,
    status: r.status,
    recalling_firm: r.recalling_firm
  }
}));

return [{
  json: {
    filename: filename,
    ai_insights: aiResponse,
    rows: excelRows.map(r => r.json)
  }
}];

