raw = _items[0]["json"]["results"]

cleaned = []
for record in raw:
    cleaned.append({
        "json": {
            "date": record.get("event_date_initiated", "unknown"),
            "product": record.get("product_description", "unknown")[:80].replace("\n", " ").replace("\r", " "),
            "reason": record.get("reason_for_recall", "unknown")[:80].replace("\n", " ").replace("\r", " "),
            "classification": record.get("classification", "unknown"),
            "status": record.get("status", "unknown"),
            "recalling_firm": record.get("recalling_firm", "unknown")[:50].replace("\n", " ")
        }
    })

return cleaned
